"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { uploadMeeting } from "@/lib/api";

export default function Home() {
  const router = useRouter();
  const [file, setFile] = useState<File | null>(null);
  const [title, setTitle] = useState("");
  const [participants, setParticipants] = useState("");
  const [notion, setNotion] = useState(false);
  const [slack, setSlack] = useState(false);
  const [linear, setLinear] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!file) {
      setError("Please select an audio file.");
      return;
    }
    setError("");
    setLoading(true);

    try {
      const formData = new FormData();
      formData.append("file", file);
      formData.append("title", title || "Untitled Meeting");
      formData.append("participants", participants);
      formData.append("push_notion", String(notion));
      formData.append("push_slack", String(slack));
      formData.append("push_linear", String(linear));

      const data = await uploadMeeting(formData);
      router.push(`/meetings/${data.meeting_id}`);
    } catch (err: any) {
      setError(err.message || "Failed to upload meeting.");
      setLoading(false);
    }
  };

  return (
    <main className="min-h-screen flex items-center justify-center p-4 relative overflow-hidden">
      {/* Background decoration */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-purple-600/30 rounded-full blur-[120px] pointer-events-none" />
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-rose-600/20 rounded-full blur-[120px] pointer-events-none" />

      <div className="glass rounded-2xl p-8 max-w-xl w-full relative z-10 shadow-2xl border border-white/10">
        <div className="text-center mb-10">
          <h1 className="text-4xl md:text-5xl font-extrabold tracking-tight mb-3">
            <span className="gradient-text">MeetMind</span>
          </h1>
          <p className="text-slate-400 text-lg">Intelligent meeting analysis and automated tracking.</p>
        </div>

        {error && (
          <div className="mb-6 p-4 bg-red-500/10 border border-red-500/30 rounded-xl text-red-400 text-sm">
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-300">Meeting Audio</label>
            <div className="flex items-center justify-center w-full">
              <label htmlFor="dropzone-file" className="flex flex-col items-center justify-center w-full h-40 border-2 border-dashed rounded-xl cursor-pointer hover:bg-slate-800/50 bg-slate-800/30 border-slate-600 hover:border-slate-500 transition-all duration-300">
                <div className="flex flex-col items-center justify-center pt-5 pb-6">
                  <svg className="w-10 h-10 mb-3 text-slate-400" aria-hidden="true" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 20 16">
                    <path stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 13h3a3 3 0 0 0 0-6h-.025A5.56 5.56 0 0 0 16 6.5 5.5 5.5 0 0 0 5.207 5.021C5.137 5.017 5.071 5 5 5a4 4 0 0 0 0 8h2.167M10 15V6m0 0L8 8m2-2 2 2"/>
                  </svg>
                  <p className="mb-2 text-sm text-slate-400">
                    <span className="font-semibold text-white">Click to upload</span> or drag and drop
                  </p>
                  <p className="text-xs text-slate-500">MP3, MP4, WAV, or M4A</p>
                  {file && (
                    <p className="mt-3 text-sm text-purple-400 font-medium bg-purple-400/10 px-3 py-1 rounded-full truncate max-w-[80%]">
                      {file.name}
                    </p>
                  )}
                </div>
                <input id="dropzone-file" type="file" className="hidden" accept=".mp3,.mp4,.wav,.m4a" onChange={(e) => e.target.files && setFile(e.target.files[0])} />
              </label>
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-300">Meeting Title</label>
            <input 
              type="text" 
              placeholder="E.g. Product Sync Q3"
              className="w-full bg-slate-800/50 border border-slate-700 text-white rounded-xl focus:ring-2 focus:ring-purple-500 focus:border-transparent block px-4 py-3 placeholder-slate-500 transition-all duration-300 outline-none" 
              value={title} 
              onChange={(e) => setTitle(e.target.value)} 
            />
          </div>

          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-300">Participants (Optional)</label>
            <input 
              type="text" 
              placeholder="Priya, Rohan, Ankit"
              className="w-full bg-slate-800/50 border border-slate-700 text-white rounded-xl focus:ring-2 focus:ring-purple-500 focus:border-transparent block px-4 py-3 placeholder-slate-500 transition-all duration-300 outline-none" 
              value={participants} 
              onChange={(e) => setParticipants(e.target.value)} 
            />
          </div>

          <div className="pt-4 space-y-3">
            <p className="text-sm font-medium text-slate-300 mb-3">Integrations</p>
            <div className="flex gap-4 flex-wrap">
              <Toggle text="Notion" checked={notion} onChange={setNotion} />
              <Toggle text="Slack" checked={slack} onChange={setSlack} />
              <Toggle text="Linear" checked={linear} onChange={setLinear} />
            </div>
          </div>

          <button 
            type="submit" 
            disabled={loading}
            className={`w-full text-white font-medium rounded-xl text-lg px-5 py-4 text-center mt-8 transition-all duration-300 shadow-[0_0_20px_rgba(139,92,246,0.3)] hover:shadow-[0_0_30px_rgba(139,92,246,0.5)] ${loading ? 'bg-slate-700 cursor-not-allowed' : 'bg-gradient-to-r from-purple-600 to-rose-600 hover:opacity-90 active:scale-[0.98]'}`}
          >
            {loading ? (
              <span className="flex items-center justify-center gap-2">
                <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                Processing...
              </span>
            ) : "Analyze Meeting"}
          </button>
        </form>
      </div>
    </main>
  );
}

function Toggle({ text, checked, onChange }: { text: string, checked: boolean, onChange: (v: boolean) => void }) {
  return (
    <label className="relative inline-flex items-center cursor-pointer group">
      <input type="checkbox" className="sr-only peer" checked={checked} onChange={(e) => onChange(e.target.checked)} />
      <div className="w-11 h-6 bg-slate-700 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full rtl:peer-checked:after:-translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:start-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-purple-600 group-hover:bg-slate-600 transition-colors"></div>
      <span className="ms-3 text-sm font-medium text-slate-300 select-none group-hover:text-white transition-colors">{text}</span>
    </label>
  );
}
